active_projects = env['project.project'].search([('active', '=', True)])
log("Refreshing costs on %d active projects" % len(active_projects))
for proj in active_projects:
    if proj.cbs_ids:
        try:
            proj.action_refresh_costs()
        except Exception as e:
            log("Failed to refresh %s: %s" % (proj.name, e))
